parameters.jsCode:
const body = $json.body;

let strategy = "";
let tone = "";
let urgency = "";
let cta = "";
let actionType = "";

const status = (body.intent || "").toLowerCase();

if (status.includes("cold")) {
  strategy = "Rebuild relationship naturally";
  tone = "friendly";
  urgency = "low";
  cta = "Start light conversation";
  actionType = "re-engage";
}

else if (status.includes("follow")) {
  strategy = "Encourage next response";
  tone = "professional";
  urgency = "medium";
  cta = "Push conversation forward";
  actionType = "send-follow-up";
}

else {
  strategy = "Maintain active relationship";
  tone = "casual";
  urgency = "low";
  cta = "Keep engagement active";
  actionType = "check-in";
}

if (body.mode === "same_tone" && body.previous_tone) {
    tone = body.previous_tone;
}
else if (body.tone_override) {
    tone = body.tone_override;
}

return [{
  json: {
    client_id: body.client_id,
    user_id: body.user_id,

    client_name: body.client_name,
    notes: body.notes,
    tags: body.tags,
    last_contacted: body.last_contacted,
    relationship_status: body.intent,
    days_since_contact: body.days_since_contact || 0,

    outreach_strategy: strategy,
    outreach_tone: tone,
    outreach_cta: cta,
    outreach_urgency: urgency,
    action_type: actionType
  }
}];

